var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>그라운드 원 도시관리국에서 안내 드립니다.</color>","JPN":"<color=#ffd34c>グラウンド・ワン、都市管理局からのお知らせです。</color>","ENG":"<color=#ffd34c>This is an announcement from Ground One, City Management.</color>","TWN":"<color=#ffd34c>Ground 1城市管理局播報通知。</color>"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>A-5 구역에서 발생한 침식 재난이 관할 태스크포스의 정화 작전 실패로 장기화될 전망입니다.</color>","JPN":"<color=#ffd34c>A-5エリアで発生した侵食災害は、管轄タスクフォースカンパニーの浄化作戦失敗により\\n長期化する見込みです。</color>","ENG":"<color=#ffd34c>The Corruption disaster in Sector A-5 is projected to continue due to the failure of the purification operations of the TASKFORCE with jurisdiction in the area.</color>","TWN":"<color=#ffd34c>由於管轄特遣勢力的淨化作戰失敗，A-5區域發生的侵蝕災難將會陷入長期化。</color>　　"},"stage":{"bg":"MAINSTREAM_000006","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>A-5 구역에 계신 시민 여러분은 가까운 대피소에서 대기해 주시기 바랍니다.</color>","JPN":"<color=#ffd34c>A-5エリアにお住まいの市民の皆様は\\nお近くの避難所に避難してください。</color>","ENG":"<color=#ffd34c>All citizens in Sector A-5 are to evacuate and stand by at the nearest shelter.</color>","TWN":"<color=#ffd34c>請A-5區域的居民儘快前往附近的避難所等待救援。</color>"},"stage":{"bg":"MAINSTREAM_000008","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......그런 이유로 우리 회사도 긴급히 정화작전에 투입되게 되었습니다.","JPN":"……というわけで、うちも浄化作戦に緊急投入されることになりました。","ENG":"And that's why we'll be joining the purification operations last minute.","TWN":"……因為這個緣故，我們公司也緊急支援了淨化作戰。"},"stage":{"bg":"HELI_NIGHT_2","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"오늘은 소대장도 비번이고 코핀 함도 수리 중이라며?","JPN":"今日は小隊長も非番だし、コフィンも修理中だよね？","ENG":"But I heard the Commander's off duty and the Coffin's being repaired today.","TWN":"但今天小隊長不是休假，科芬艦也在修理嗎？"},"stage":{"bg":"HELI_NIGHT_2","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"정말 우리 둘만 보내도 괜찮은 거야?","JPN":"本当に私たち二人だけでいいの？","ENG":"Are you sure you can send just the two of us?","TWN":"只派我們兩個人去真的沒問題嗎？"},"stage":{"bg":"HELI_NIGHT_2","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양도 최근에 실전 경험이 많이 늘었으니까요.","JPN":"ミナさんも実戦経験が増えましたからね。","ENG":"Well, you've had ample experience in real combat lately.","TWN":"沒問題，因為米娜小姐最近也積累了不少實戰經驗啊。"},"stage":{"bg":"HELI_NIGHT_2","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"리플레이서 사건까지 포함하면 어지간한 베테랑 경력 못지 않을 겁니다.","JPN":"リプレイサー事件まで含めると、ベテラン顔負けの経歴だと思いますよ。","ENG":"I'm sure you're as experienced as any veteran Counter if you include your involvement in the Replacer incident.","TWN":"加上克隆事件，妳的經驗已經不亞於一般的老手了。"},"stage":{"bg":"HELI_NIGHT_2","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그, 그 정도까지는 아닌데......","JPN":"お、大げさだな……","ENG":"I-I wouldn't go that far...","TWN":"沒、沒有那麼厲害啦……"},"stage":{"bg":"HELI_NIGHT_2","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그래도 평소 같았으면 둘만 보내는 일은 없었겠죠.","JPN":"でも、普段であればたった二人だけを派遣するなんてしなかったでしょう。","ENG":"Under normal circumstances, I wouldn't be sending just you two.","TWN":"若在平時，肯定不會只派你們兩個人去的。"},"stage":{"bg":"HELI_NIGHT_2","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 이번에는 다른 회사와의 연합 작전이니, 특별히 위험한 일은 없을 겁니다.","JPN":"今回は他社との合同作戦ですので、特に危険はないと思います。","ENG":"But I'm sure it won't be too dangerous this time, since we'll be working alongside another company.","TWN":"但這次是跟其他公司的聯合作戰，應該不會有什麼特別危險的事情才對。"},"stage":{"bg":"HELI_NIGHT_2","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"참고로 스승님이 부재중인 만큼 소대장 몫의 전투 수당도 두 사람에게 지급될 예정입니다.","JPN":"ちなみに師匠がいないため、小隊長の分の戦闘手当が二人に支給される予定です。","ENG":"And just so you know, since the Master is absent, her cut as the commander will be paid out to you two instead.","TWN":"另外，因為師父不在，小隊長的那份戰鬥津貼也會發給你們。"},"stage":{"bg":"HELI_NIGHT_2","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그거 정말이지?! 그럼 힘을 좀 더 내야겠는걸?","JPN":"本当！？　張り切っていかないと！","ENG":"For real?! Then I'd better step up my game!","TWN":"真的嗎？！那我得更加努力了！"},"stage":{"bg":"HELI_NIGHT_2","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"좋아요. 그럼......","JPN":"いいでしょう。では……","ENG":"Good. Now...","TWN":"好，那麼……"},"stage":{"bg":"HELI_NIGHT_2","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};